class ExamRoom:
    def __init__(self, n):
        self.n = n; self.seats = []
    def seat(self):
        if not self.seats: res = 0
        else:
            mx = self.seats[0]; res = 0
            for i in range(len(self.seats)-1):
                d = (self.seats[i+1] - self.seats[i]) // 2
                if d > mx: mx = d; res = self.seats[i] + d
            if self.n - 1 - self.seats[-1] > mx: res = self.n - 1
        bisect.insort(self.seats, res); return res
    def leave(self, p):
        self.seats.remove(p)

